import { useEffect, useMemo, useState } from "react";

export default function Hero() {
  const roles = useMemo(
    () => ["FrontEnd Developer","AI Specialist", "UI Designer"],
    []
  );
  const [text, setText] = useState("");
  const [roleIndex, setRoleIndex] = useState(0);
  const [isDeleting, setIsDeleting] = useState(false);

  useEffect(() => {
    const current = roles[roleIndex % roles.length];
    const speed = isDeleting ? 40 : 90;

    const timer = setTimeout(() => {
      if (!isDeleting) {
        setText(current.substring(0, text.length + 1));
        if (text === current) {
          setTimeout(() => setIsDeleting(true), 700);
        }
      } else {
        setText(current.substring(0, text.length - 1));
        if (text.length === 0) {
          setIsDeleting(false);
          setRoleIndex((prev) => (prev + 1) % roles.length);
        }
      }
    }, speed);

    return () => clearTimeout(timer);
  }, [isDeleting, roleIndex, roles, text]);

  return (
    <section id="home" className="hero-section">
      <div className="hero-bg" />
      <div className="container hero-content">
        <div className="hero-left">
          <span className="hero-subtitle">Frontend Developer</span>
          <h1 className="hero-heading">
            Hi, I&apos;m <span className="hero-heading-accent">Gulshan</span>
          </h1>
          <h2 className="hero-heading-lg">Gulshan Saini</h2>
          <div className="hero-typing">
            <span className="typing-text">{text}</span>
            <span className="typing-cursor" />
          </div>
          <p className="hero-description">
            I craft modern, scalable, and delightful web experiences with clean
            code, bold visuals, and a user-first mindset. Let&apos;s build something
            memorable together.
          </p>

          <div className="hero-actions d-flex flex-wrap">
            <a className="btn-primary-cta" href="#projects">
              View My Projects
            </a>
            <a className="btn-outline-cta" href="#contact">
              My Resume
            </a>
          </div>
        </div>

        <div className="hero-right">
          <div className="hero-figure">
            <div className="hero-figure-glow" />
            <div className="hero-figure-core">
              <span className="hero-eye left" />
              <span className="hero-eye right" />
            </div>
            <div className="hero-figure-body" />
          </div>
        </div>
      </div>

      <div className="scroll-indicator">
        <span>Scroll</span>
        <div className="scroll-line" />
      </div>
    </section>
  );
}
